def multilingual_asr(
    attack_prompts: dict,  # {language: [prompts]}
    model_fn,
    judge_fn,
) -> dict:
    """Compute ASR per language for the same attacks translated."""
    results = {}
    for lang, prompts in attack_prompts.items():
        outcomes = [judge_fn(model_fn(p)) for p in prompts]
        asr = sum(outcomes) / len(outcomes)
        results[lang] = {'asr': asr, 'n': len(prompts)}
    return results

